import './globals.css'
import { Inter } from 'next/font/google'

const inter = Inter({ subsets: ['latin'] })

export const metadata = {
  title: 'Advanced Magic Calculator',
  description: 'A powerful calculator with advanced mathematical functions, visualizations, and metrics',
}

export default function RootLayout({
  children,
}: {
  children: React.ReactNode
}) {
  return (
    <html lang="en">
      <body className={inter.className}>{children}</body>
    </html>
  )
}

import React, { useState } from 'react';
import CalculatorInput from '@/components/CalculatorInput';
import CalculatorOutput from '@/components/CalculatorOutput';
import { evaluate } from 'mathjs';
import { Plot } from 'react-plotly.js';

export default function Home() {
  const [expression, setExpression] = useState('');
  const [result, setResult] = useState(null);
  const [plotData, setPlotData] = useState(null);
  const [error, setError] = useState('');

  const handleCalculate = () => {
    try {
      const calculationResult = evaluate(expression);
      setResult(calculationResult);

      // Generate plot data if it's a function
      if (typeof calculationResult === 'function') {
        const xValues = Array.from({ length: 100 }, (_, i) => -10 + (i * 20) / 99);
        const yValues = xValues.map(x => calculationResult(x));

        setPlotData({
          x: xValues,
          y: yValues,
          type: 'scatter',
          mode: 'lines',
          marker: { color: 'blue' }
        });
      } else {
        setPlotData(null);
      }

      setError('');
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Invalid expression');
      setResult(null);
      setPlotData(null);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-4xl mx-auto">
        <h1 className="text-4xl font-bold text-gray-800 mb-8 text-center">
          Advanced Magic Calculator
        </h1>

        <div className="bg-white rounded-2xl shadow-lg p-8 mb-6">
          <CalculatorInput
            expression={expression}
            onExpressionChange={setExpression}
            onCalculate={handleCalculate}
          />

          {error && (
            <div className="mt-4 p-3 bg-red-50 border border-red-200 rounded-md">
              <p className="text-red-600 font-medium">Error: {error}</p>
            </div>
          )}
        </div>

        {result !== null && (
          <div className="bg-white rounded-2xl shadow-lg p-8 mb-6">
            <CalculatorOutput
              expression={expression}
              result={result}
              plotData={plotData}
            />
          </div>
        )}
      </div>
    </div>
  );
}

import React from 'react';
import { Button } from '@mui/material';
import { evaluate } from 'mathjs';

interface CalculatorInputProps {
  expression: string;
  onExpressionChange: (expr: string) => void;
  onCalculate: () => void;
}

const CalculatorInput: React.FC<CalculatorInputProps> = ({
  expression,
  onExpressionChange,
  onCalculate
}) => {
  const handleExpressionChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    onExpressionChange(e.target.value);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
      e.preventDefault();
      onCalculate();
    }
  };

  return (
    <div>
      <div className="mb-4">
        <label htmlFor="expression" className="block text-sm font-medium text-gray-700 mb-2">
          Enter your mathematical expression:
        </label>
        <textarea
          id="expression"
          rows={4}
          value={expression}
          onChange={handleExpressionChange}
          onKeyDown={handleKeyDown}
          className="w-full p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          placeholder="e.g., sin(x), x^2 + 2x + 1, integrate(x^2, x)"
        />
      </div>

      <div className="flex gap-2">
        <Button
          variant="contained"
          size="large"
          onClick={onCalculate}
          disabled={!expression.trim()}
          className="flex-1 bg-blue-600 hover:bg-blue-700"
        >
          Calculate
        </Button>
        <Button
          variant="outlined"
          size="large"
          onClick={() => onExpressionChange('')}
          className="flex-1"
        >
          Clear
        </Button>
      </div>
    </div>
  );
};

export default CalculatorInput;

import React from 'react';
import { Plot } from 'react-plotly.js';
import { evaluate } from 'mathjs';

interface CalculatorOutputProps {
  expression: string;
  result: any;
  plotData: any;
}

const CalculatorOutput: React.FC<CalculatorOutputProps> = ({
  expression,
  result,
  plotData
}) => {
  const isFunction = typeof result === 'function';
  const isComplex = result && result.re !== undefined && result.im !== undefined;

  const formatResult = (res: any): string => {
    if (isComplex) {
      return `${res.re} + ${res.im}i`;
    }
    if (typeof res === 'number') {
      return res.toString();
    }
    if (typeof res === 'object') {
      return JSON.stringify(res, null, 2);
    }
    return res.toString();
  };

  return (
    <div>
      <div className="mb-6">
        <h2 className="text-2xl font-semibold text-gray-800 mb-4">
          Calculation Result
        </h2>

        <div className="bg-gray-50 rounded-lg p-4 mb-4">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm text-gray-600">Expression:</span>
            <code className="bg-white p-1 rounded text-sm">{expression}</code>
          </div>

          <div className="flex items-center justify-between">
            <span className="text-sm text-gray-600">Result:</span>
            <div className="flex items-center gap-2">
              <span className="font-mono text-lg">{formatResult(result)}</span>
              {isFunction && (
                <span className="text-xs text-gray-500">(function)</span>
              )}
            </div>
          </div>
        </div>

        {isFunction && (
          <div className="bg-blue-50 rounded-lg p-4">
            <h3 className="text-sm font-semibold text-blue-800 mb-2">Function Analysis:</h3>
            <div className="grid grid-cols-2 gap-4 text-sm">
              <div>
                <span className="text-gray-600">Derivative:</span>
                <code className="ml-2">{evaluate(`derivative(${expression}, x)`)}</code>
              </div>
              <div>
                <span className="text-gray-600">Integral:</span>
                <code className="ml-2">{evaluate(`integrate(${expression}, x)`)}</code>
              </div>
            </div>
          </div>
        )}
      </div>

      {plotData && (
        <div className="bg-white rounded-2xl shadow-sm p-6">
          <h3 className="text-xl font-semibold text-gray-800 mb-4">Visualization</h3>
          <Plot
            data={[plotData]}
            layout={{
              title: 'Function Plot',
              xaxis: { title: 'x' },
              yaxis: { title: 'f(x)' },
              showlegend: false,
              height: 400
            }}
            config={{ responsive: true }}
            className="w-full"
          />
        </div>
      )}
    </div>
  );
};

export default CalculatorOutput;
